args.sparql:
SELECT ?locationLabel WHERE {
  ?drive rdfs:label "17 Mile Drive"@en .
  ?drive wdt:P131 ?location .
  ?location rdfs:label ?locationLabel .
  FILTER(LANG(?locationLabel) = 'en')
}

SELECT ?startLabel WHERE {
  wd:Q197257 wdt:P150 ?start .
  ?start rdfs:label ?startLabel .
  FILTER(LANG(?startLabel) = 'en')
}

SELECT ?startLabel WHERE {
  wd:Q197257 wdt:P1527 ?start.
  ?start rdfs:label ?startLabel.
  FILTER(LANG(?startLabel) = 'en')
}

